(function () {
  var form = document.querySelector('[data-search-form]');
  var liveInput = document.querySelector('[data-live-search]');
  var categorySelect = document.querySelector('[data-category-select]');
  var results = document.querySelector('[data-search-results]');

  if (!results || !window.SEARCH_INDEX) {
    return;
  }

  var params = new URLSearchParams(window.location.search);
  var initialQuery = params.get('q') || '';

  if (form && form.q) {
    form.q.value = initialQuery;
  }

  if (liveInput) {
    liveInput.value = initialQuery;
  }

  function normalize(value) {
    return String(value || '').trim().toLowerCase();
  }

  function render(items) {
    results.innerHTML = items.slice(0, 180).map(function (item) {
      var tags = (item.tags || []).slice(0, 3).map(function (tag) {
        return '<span>' + escapeHtml(tag) + '</span>';
      }).join('');

      return [
        '<article class="movie-card">',
        '<a class="poster-wrap" href="' + escapeAttr(item.url) + '" aria-label="' + escapeAttr(item.title) + '">',
        '<img src="' + escapeAttr(item.poster) + '" alt="' + escapeAttr(item.title) + '" loading="lazy">',
        '<span class="poster-play">▶</span>',
        '</a>',
        '<div class="movie-card-body">',
        '<div class="movie-meta-line"><span>' + escapeHtml(item.year) + '</span><span>' + escapeHtml(item.region) + '</span><span>' + escapeHtml(item.type) + '</span></div>',
        '<h3><a href="' + escapeAttr(item.url) + '">' + escapeHtml(item.title) + '</a></h3>',
        '<p>' + escapeHtml(item.oneLine) + '</p>',
        '<div class="tag-list">' + tags + '</div>',
        '</div>',
        '</article>'
      ].join('');
    }).join('');
  }

  function applySearch() {
    var keyword = normalize(liveInput && liveInput.value);
    var category = categorySelect ? categorySelect.value : '';
    var items = window.SEARCH_INDEX.filter(function (item) {
      var haystack = normalize([
        item.title,
        item.year,
        item.region,
        item.type,
        item.genre,
        item.categoryName,
        (item.tags || []).join(' '),
        item.oneLine
      ].join(' '));
      var keywordOk = !keyword || haystack.indexOf(keyword) !== -1;
      var categoryOk = !category || item.category === category;
      return keywordOk && categoryOk;
    });

    if (!keyword && !category) {
      items = window.SEARCH_INDEX.slice(0, 60);
    }

    render(items);
  }

  function escapeHtml(value) {
    return String(value || '').replace(/[&<>"]/g, function (match) {
      return {
        '&': '&amp;',
        '<': '&lt;',
        '>': '&gt;',
        '"': '&quot;'
      }[match];
    });
  }

  function escapeAttr(value) {
    return escapeHtml(value).replace(/'/g, '&#39;');
  }

  if (form) {
    form.addEventListener('submit', function (event) {
      event.preventDefault();
      if (liveInput && form.q) {
        liveInput.value = form.q.value;
      }
      applySearch();
    });
  }

  if (liveInput) {
    liveInput.addEventListener('input', applySearch);
  }

  if (categorySelect) {
    categorySelect.addEventListener('change', applySearch);
  }

  applySearch();
})();
